        AsyncGPUReadback.Request(vertexBuffer, (AsyncGPUReadbackRequest req) =>
        {
            if (req.hasError)
            {
                Debug.LogError("AsyncGPUReadback error for vertices");
            }
            else
            {
                var data = req.GetData<Vector3>();
                data.CopyTo(verts);
            }
            Debug.Log("Vertex readback completed");
            // Now request normals — do this on the callback thread to stagger GPU/CPU work
            AsyncGPUReadback.Request(normalBuffer, (AsyncGPUReadbackRequest req2) =>
            {
                if (req2.hasError)
                {
                    Debug.LogError("AsyncGPUReadback error for normals");
                }
                else
                {
                    var data2 = req2.GetData<Vector3>();
                    data2.CopyTo(normals);
                }
                Debug.Log("Normal readback completed");
                ReadbackDone();
            });
        });
    }

    private void ReadbackDone()
    {
        pendingReadbacks--;
        if (pendingReadbacks == 0)
        {
            // All data received, finalize mesh on main thread
            FinalizeMesh();
            // Now that verts are populated, generate the biome texture
            generateTexture();
        }
        Debug.Log("Readback completed, pending readbacks: " + pendingReadbacks);
    }

    private void texture()
    { 
        for (int y = 0; y < textureres; y++)
        {
            for (int x = 0; x < textureres; x++)
            {
                biomeMap.SetPixel(x, y, new Color32((byte)color[x + y * textureres].x, (byte)color[x + y * textureres].y, (byte)color[x + y * textureres].z, 255));
            }
        }
        biomeMap.filterMode = FilterMode.Bilinear;
        biomeMap.wrapMode = TextureWrapMode.Clamp;
        biomeMap.Apply();
    }
    private void generateTexture()
    {
        int size = textureres * textureres;

        color = new Vector3Int[size];
        trees = new Vector3[size];

        int kernel = biomeCS.FindKernel("BiomeCSMain");

        colorBuffer = new GraphicsBuffer(GraphicsBuffer.Target.Structured, size, sizeof(int) * 3);
        treeBuffer = new GraphicsBuffer(GraphicsBuffer.Target.Structured, size, sizeof(float) * 3);

        biomeCS.SetBuffer(kernel, "colors", colorBuffer);
        biomeCS.SetBuffer(kernel, "trees", treeBuffer);

        biomeCS.SetInt("terrainresolution", resolution);
        biomeCS.SetInt("textureresolution", textureres);

        biomeCS.SetFloat("xOffset", transform.position.x);
        biomeCS.SetFloat("yOffset", transform.position.z);
        biomeCS.SetFloat("maxAmp", maxAmplitude);

        biomeCS.SetFloat("biomeFrequency", biomeFrequency);
        biomeCS.SetInt("biomeCount", biomeData.biomes.Count);

        biomeCS.SetInt("seed", seed);

        heightBuffer = new ComputeBuffer(resolution * resolution, sizeof(float));
        float[] heights = new float[resolution * resolution];
        for(int i = 0; i < resolution * resolution; i++)
        {
            heights[i] = verts[i].y;
        }
        heightBuffer.SetData(heights);
        biomeCS.SetBuffer(kernel, "heights", heightBuffer);

        computeBuffer(sizeof(int), elev, biomeData.biomes.Count, biomeCS, kernel, "elevations");
        computeBuffer(sizeof(int), moist, biomeData.biomes.Count, biomeCS, kernel, "moistures");
        computeBuffer(sizeof(int), cont, biomeData.biomes.Count, biomeCS, kernel, "continentalnesses");
        computeBuffer(sizeof(int) * 3, col, biomeData.biomes.Count, biomeCS, kernel, "biomecolors");

        biomeCS.GetKernelThreadGroupSizes(kernel, out uint tgx, out uint tgy, out uint tgz);
        int groupsX = Mathf.CeilToInt((float)textureres / tgx);
        int groupsY = Mathf.CeilToInt((float)textureres / tgy);
        biomeCS.Dispatch(kernel, groupsX, groupsY, 1);

        // Request color first, then request trees after colors are applied — chains readbacks
        AsyncGPUReadback.Request(colorBuffer, (AsyncGPUReadbackRequest req) =>
        {
            if (req.hasError)
            {
                Debug.LogError("AsyncGPUReadback error for biome colors");
            }
            else
            {
                var data = req.GetData<Vector3Int>();
                data.CopyTo(color);
                // Apply the texture now that colors are available
                texture();
            }
            Debug.Log("Biome color readback completed");

            // Chain tree readback after color is applied to avoid simultaneous readbacks
            AsyncGPUReadback.Request(treeBuffer, (AsyncGPUReadbackRequest req2) =>
            {
                if (req2.hasError)
                {
                    Debug.LogError("AsyncGPUReadback error for biome trees");
                }
                else
                {
                    var data2 = req2.GetData<Vector3>();
                    data2.CopyTo(trees);
                    // Release height buffer now that both computations are done
                    if (heightBuffer != null) { heightBuffer.Release(); heightBuffer = null; }
                    // Spawn trees over multiple frames to avoid hitching
                    populateTrees();
                }
                Debug.Log("Biome tree readback completed");
            });
        });


    }        
    private void populateTrees()
    {
        // Spawn trees over multiple frames to avoid frame hitching
        StartCoroutine(SpawnTrees());
    }

    private IEnumerator SpawnTrees()
    {
        if (trees == null || treePrefab == null) yield break;
        int batchSize = 50; // number of trees to instantiate per frame
        int count = trees.Length;
        for (int i = 0; i < count; i++)
        {
            Vector3 tree = trees[i];
            if (tree.y > 0)
            {
                Instantiate(treePrefab, new Vector3(tree.x, tree.y, tree.z), Quaternion.identity);
            }
            if (i % batchSize == 0) // yield occasionally to spread workload
            {
                yield return null;
            }
        }
    }
    private void computeBuffer(int typesize, Array a, int size, ComputeShader CS, int kernel, string name)
    {
        ComputeBuffer buffer = new ComputeBuffer(size, typesize);
        buffer.SetData(a);
        CS.SetBuffer(kernel, name, buffer);
    }
    private void populateArrays()
    {   
        int length = biomeData.biomes.Count;

        elev = new int[length];
        moist = new int[length];
        cont = new int[length];
        col = new Vector3Int[length];

        for(int i = 0; i < length; i++)
        {
            elev[i] = (int) biomeData.biomes[i].elevation;
            moist[i] = (int) biomeData.biomes[i].moisture;
            cont[i] = (int) biomeData.biomes[i].continentaless;
            col[i] = new Vector3Int(Mathf.FloorToInt(biomeData.biomes[i].color.r * 255), Mathf.FloorToInt(biomeData.biomes[i].color.g * 255),Mathf.FloorToInt(biomeData.biomes[i].color.b * 255));
        }
    }
}

using System;
using System.Collections.Generic;
using System.ComponentModel;
using UnityEditor.Rendering;
using UnityEngine;

public class ChunkLoader : MonoBehaviour
{
    public Transform player;
    Vector2Int playerPosition;

    public GameObject terrainPrefab;
    public GameObject lowResTerrainPrefab;

    [Header("Chunk Settings")]
    // Must match terrain heightmap resolution
    [Range(2, 128)]
    public int viewDistanceInChunks = 2;
    public int chunkSize = 64;
    public int chunkResolution = 64;
    public int textureResolution = 64;
    [Range(0f,0.1f)]
    public float biomeScale;
    public Transform parentFolder;
    public Transform lowResParentFolder;

    public int seed = 0;

    private Dictionary<Vector2Int, GameObject> loadedChunks = new Dictionary<Vector2Int, GameObject>();
    private Dictionary<Vector2Int, GameObject> allGeneratedChunks = new Dictionary<Vector2Int, GameObject>();
    private Dictionary<Vector2Int, GameObject> loadedLowResChunks = new Dictionary<Vector2Int, GameObject>();
    private Dictionary<Vector2Int, GameObject> allGeneratedLowResChunks = new Dictionary<Vector2Int, GameObject>();

    private List<Vector2Int> keystoremove = new List<Vector2Int>();
    private List<Vector2Int> lowreskeystoremove = new List<Vector2Int>();

    // Queues to stagger chunk generation across frames
    private Queue<Vector2Int> chunkGenerationQueue = new Queue<Vector2Int>();
    private Queue<Vector2Int> lowResGenerationQueue = new Queue<Vector2Int>();
    private HashSet<Vector2Int> queuedHighRes = new HashSet<Vector2Int>();
    private HashSet<Vector2Int> queuedLowRes = new HashSet<Vector2Int>();

    [Header("Streaming Settings")]
    [Tooltip("Maximum number of high-res chunks to generate per frame. Set to 1 for sequential generation.")]
    public int chunksPerFrame = 1;
    [Tooltip("Maximum number of low-res chunks to generate per frame.")]
    public int lowResChunksPerFrame = 2;




    void Start()
    {
        playerPosition = new Vector2Int(Mathf.FloorToInt(player.position.x / chunkSize), Mathf.FloorToInt(player.position.z / chunkSize));

        System.Random rand = new System.Random(seed);
        seed = rand.Next();
    }
    void Update()
    {
        playerPosition = new Vector2Int(Mathf.FloorToInt(player.position.x / chunkSize), Mathf.FloorToInt(player.position.z / chunkSize));
        loadChunks();
        unloadChunks();
        ProcessGenerationQueues();
    }

    private void loadChunks()
    {
        for(int x = -viewDistanceInChunks; x <= viewDistanceInChunks; x++)
        {
            for(int z = -viewDistanceInChunks; z <= viewDistanceInChunks; z++)
            {
                Vector2Int t = playerPosition + new Vector2Int(x,z);
                double dist = Math.Sqrt(x*x + z*z);

                if(dist < viewDistanceInChunks * 0.5f && !loadedChunks.ContainsKey(t))
                {
                    EnqueueChunk(t);
                } else if(dist >= viewDistanceInChunks * 0.5f && dist <= viewDistanceInChunks && !loadedLowResChunks.ContainsKey(t))
                {
                    EnqueueLowResChunk(t);
                }
            }
        }
    }

    private void EnqueueChunk(Vector2Int pos)
    {
        if (queuedHighRes.Contains(pos)) return;
        queuedHighRes.Add(pos);
        chunkGenerationQueue.Enqueue(pos);
    }

    private void EnqueueLowResChunk(Vector2Int pos)
    {
        if (queuedLowRes.Contains(pos)) return;
        queuedLowRes.Add(pos);
        lowResGenerationQueue.Enqueue(pos);
    }

    private void ProcessGenerationQueues()
    {
        // Process a limited number of high-res chunks first
        int processed = 0;
        while (processed < chunksPerFrame && chunkGenerationQueue.Count > 0)
        {
            var pos = chunkGenerationQueue.Dequeue();
            queuedHighRes.Remove(pos);
            // double-check we still need it
            if (!loadedChunks.ContainsKey(pos))
            {
                generateChunk(pos);
            }
            processed++;
        }

        // Process low-res queue
        int processedLow = 0;
        while (processedLow < lowResChunksPerFrame && lowResGenerationQueue.Count > 0)
        {
            var pos = lowResGenerationQueue.Dequeue();
            queuedLowRes.Remove(pos);
            if (!loadedLowResChunks.ContainsKey(pos))
            {
                generateLowResChunk(pos);
            }
            processedLow++;
        }
    }

    private void unloadChunks()
    {

        foreach(var chunk in loadedLowResChunks)
        {
            int relx = Mathf.Abs(chunk.Key.x - playerPosition.x);
            int relz = Mathf.Abs(chunk.Key.y - playerPosition.y);

            double dist = Math.Sqrt(relx*relx + relz*relz);

            if(dist > viewDistanceInChunks || dist < viewDistanceInChunks * 0.5f)
            {
                chunk.Value.SetActive(false);
                lowreskeystoremove.Add(chunk.Key);
                // Debug.Log("Unloaded Chunk");
            }
        
        }

        foreach(var chunk in loadedChunks)
        {
            int relx = Mathf.Abs(chunk.Key.x - playerPosition.x);
            int relz = Mathf.Abs(chunk.Key.y - playerPosition.y);

            double dist = Math.Sqrt(relx*relx + relz*relz);

            

            if(dist >= viewDistanceInChunks * 0.5f)
            {
                chunk.Value.SetActive(false);
                keystoremove.Add(chunk.Key);
            }
            
        }
        
        foreach(var key in keystoremove)
        {
            loadedChunks.Remove(key);
        }
        keystoremove.Clear();

        foreach(var key in lowreskeystoremove)
        {
            loadedLowResChunks.Remove(key);
        }
        lowreskeystoremove.Clear();
    }

    private void generateChunk(Vector2Int pos)
    {

        if(!allGeneratedChunks.ContainsKey(pos))
        {
            GameObject ter = Instantiate(terrainPrefab, new Vector3(pos.x * chunkSize , 0, pos.y * chunkSize), Quaternion.identity);
            ter.name = "Chunk_" + pos.x + "_" + pos.y;
            ter.transform.parent = parentFolder;
            ter.GetComponent<ProcedualGenerator>().Init(chunkSize, Mathf.FloorToInt(chunkResolution), seed, textureResolution);
            loadedChunks.Add(pos, ter);
            allGeneratedChunks.Add(pos, ter);
        } else
        {
            allGeneratedChunks[pos].SetActive(true);
            loadedChunks.Add(pos, allGeneratedChunks[pos]);
        }

    }

    private void generateLowResChunk(Vector2Int pos)
    {
        if(!allGeneratedLowResChunks.ContainsKey(pos))
        {
            GameObject ter = Instantiate(lowResTerrainPrefab != null ? lowResTerrainPrefab : terrainPrefab, new Vector3(pos.x * chunkSize , 0, pos.y * chunkSize), Quaternion.identity);
            ter.name = "LowResChunk_" + pos.x + "_" + pos.y;
            ter.transform.parent = lowResParentFolder;
            ter.GetComponent<ProcedualGenerator>().Init(chunkSize, Mathf.FloorToInt(chunkResolution * 0.5f), seed, Mathf.FloorToInt(textureResolution * 0.5f));
            loadedLowResChunks.Add(pos, ter);
            allGeneratedLowResChunks.Add(pos, ter);
        } else
        {
            allGeneratedLowResChunks[pos].SetActive(true);
            loadedLowResChunks.Add(pos, allGeneratedLowResChunks[pos]);
        }
    }

    void regenerateTerrain()
    {
        loadedChunks.Clear();
        foreach(var chunk in allGeneratedChunks)
        {
            Destroy(chunk.Value);
        }
        allGeneratedChunks.Clear();
        loadedLowResChunks.Clear();
        foreach(var chunk in allGeneratedLowResChunks)
        {
            Destroy(chunk.Value);
        }
        allGeneratedLowResChunks.Clear();
    }
}

